                  <p className={styles.cardDesc}>{event.description}</p>
                  <Link href={`/events/${event.id}`} className={styles.viewLink} id={`vol-event-${event.id}`}>
                    View Details ÔåÆ
                  </Link>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

